function polar_data = parse_vsp_results(polar_file)
% PARSE_VSP_RESULTS  Parse VSPAero polar output file into MATLAB matrix.
%   polar_data = parse_vsp_results(polar_file)
%
%   Reads the .polar file generated by VSPAero and extracts the
%   aerodynamic coefficients.
%
%   Input:
%     polar_file - Path to the VSPAero .polar output file
%
%   Output:
%     polar_data - [n_alpha x 7] matrix with columns:
%                  [Alpha, Beta, CL, CDi, CDo, CDtot, CS]
%                  Simplified: returns [Alpha, CL, CDtot] if full data unavailable
%
%   The .polar file format (VSPAero v3.x+):
%     Line 1: Header "AoA, Beta, CL, CDi, CDo, CDtot, ..."
%     Line 2+: Numeric data

    polar_data = [];

    if ~exist(polar_file, 'file')
        warning('parse_vsp_results: File not found: %s', polar_file);
        return;
    end

    % --- Read file ---
    fid = fopen(polar_file, 'r');
    if fid == -1
        warning('parse_vsp_results: Cannot open file: %s', polar_file);
        return;
    end

    % Read all lines
    raw_lines = {};
    while ~feof(fid)
        line = fgetl(fid);
        if ischar(line)
            raw_lines{end+1} = strtrim(line); %#ok<AGROW>
        end
    end
    fclose(fid);

    if isempty(raw_lines)
        warning('parse_vsp_results: Empty file: %s', polar_file);
        return;
    end

    % --- Find header line (contains 'AoA' or 'Alpha') ---
    header_idx = 0;
    for i = 1:numel(raw_lines)
        if contains(raw_lines{i}, 'AoA', 'IgnoreCase', true) || ...
           contains(raw_lines{i}, 'Alpha', 'IgnoreCase', true)
            header_idx = i;
            break;
        end
    end

    if header_idx == 0
        % No header found, try reading as pure numeric
        try
            polar_data = load(polar_file);
            polar_data = polar_data(:, [1, 3, 6]);  % Alpha, CL, CDtot
        catch
            warning('parse_vsp_results: Cannot parse file format.');
        end
        return;
    end

    % --- Parse header to identify columns ---
    header = raw_lines{header_idx};
    % Remove comment characters
    header = regexprep(header, '^[#%/]+\s*', '');
    col_names = strsplit(header, {',', '\t', ' '});
    col_names = col_names(~cellfun('isempty', col_names));

    % Identify key columns
    idx_alpha = find_column(col_names, {'AoA', 'Alpha', 'alpha'});
    idx_CL    = find_column(col_names, {'CL', 'Cl'});
    idx_CDtot = find_column(col_names, {'CDtot', 'CDTotal', 'CD', 'Cd'});
    idx_CDi   = find_column(col_names, {'CDi', 'Cdi'});

    % --- Parse numeric data ---
    data_lines = raw_lines(header_idx+1:end);
    n_data = numel(data_lines);
    n_cols = numel(col_names);

    raw_data = zeros(n_data, n_cols);
    valid_rows = 0;

    for i = 1:n_data
        line = data_lines{i};
        if isempty(line) || line(1) == '#' || line(1) == '%'
            continue;
        end
        vals = str2double(strsplit(line, {',', '\t', ' '}));
        vals = vals(~isnan(vals));
        if numel(vals) >= max([idx_alpha, idx_CL, idx_CDtot])
            valid_rows = valid_rows + 1;
            raw_data(valid_rows, 1:numel(vals)) = vals;
        end
    end

    raw_data = raw_data(1:valid_rows, :);

    if valid_rows == 0
        warning('parse_vsp_results: No valid data rows found.');
        return;
    end

    % --- Extract key columns ---
    alpha_col = raw_data(:, idx_alpha);
    CL_col    = raw_data(:, idx_CL);
    CD_col    = raw_data(:, idx_CDtot);

    % Return simplified [Alpha, CL, CD] format
    polar_data = [alpha_col, CL_col, CD_col];

    % Validate data
    if any(CD_col < 0)
        warning('parse_vsp_results: Negative drag values detected. Check mesh/input.');
    end

end

%% ========================================================================
function idx = find_column(col_names, search_terms)
% FIND_COLUMN  Find index of column matching any search term.
    idx = 0;
    for i = 1:numel(col_names)
        for j = 1:numel(search_terms)
            if strcmpi(strtrim(col_names{i}), search_terms{j})
                idx = i;
                return;
            end
        end
    end
    if idx == 0
        idx = 1;  % Default to first column if not found
    end
end
